227	        assert(self.mode == .literal or self.mode == .telex);
228	
229	        // Should never set literal_index in .literal mode.
230	        if (self.mode == .literal) {
231	            assert(self.literal_index == null);
232	        }
233	
234	        if (self.literal_index) |literal_index| {
235	            // When literal_index is set, mode must be .telex.
236	            assert(self.mode == .telex);
237	            // The literal_index value must be in range null or 0 -> 16 (buffer_effective length)
238	            // because we won't process Vietnamese input outside the buffer_effective.
239	            assert(literal_index <= self.buffer_effective.len);
240	            // The literal_index value must be less than buffer length.
241	            assert(literal_index < self.buffer_length);
242	        }
243	
244	        switch (c) {
245	            'A', 'a' => { // circumflex.
246	                if (self.literal_index != null or self.mode == .literal) {
247	                    // Enable literal input when literal_index is set or on literal mode. The
248	                    // literal_index is also set when the word starts with non-Vietnamese onsets.
249	
250	                    // Check if we can add new span for input character.
251	                    if (self.buffer_length < self.buffer_effective.len) {
252	                        // Add character to span.
253	                        self.buffer_effective[self.buffer_length] = Span.init(c);
254	                    }
255	                    // Increase the buffer length for tracking, we will need it went handling backspace.
256	                    self.buffer_length = self.buffer_length + 1;
257	
258	                    // Set modification index to null because we didn't modify any existing span.
259	                    self.buffer_modification_index = null;
260	                } else {
261	                    // buffer_length must inbound of buffer_effective.
262	                    assert(self.buffer_length < self.buffer_effective.len);
263	
264	                    // literal_index must not be set in order to process Vietnamese input.
265	                    assert(self.literal_index == null);
266	
267	                    // Vietnamese input.
268	                    // Possible cases:
269	                    // - circumplex.
270	                    // - cancel circumflex.
271	                    // - plain append.
272	
273	                    if (self.buffer_length == 0 or (self.buffer_effective[self.buffer_length - 1].base != std.ascii.toUpper(c) and self.buffer_effective[self.buffer_length - 1].base != std.ascii.toLower(c))) {
274	                        // Plain append when start of the buffer or the previous character don't match
275	                        // circumflex rules.
276	
277	                        // Check if we can add new span for input character.
278	                        if (self.buffer_length < self.buffer_effective.len) {
279	                            // Add character to span.
280	                            self.buffer_effective[self.buffer_length] = Span.init(c);
281	                        }
282	                        // Increase the buffer length for tracking, we will need it went handling
283	                        // backspace.
284	                        self.buffer_length = self.buffer_length + 1;
285	
286	                        // Set modification index to null because we didn't modify any existing span.
287	                        self.buffer_modification_index = null;
288	                    } else if ((self.buffer_effective[self.buffer_length - 1].base == std.ascii.toUpper(c) or self.buffer_effective[self.buffer_length - 1].base == std.ascii.toLower(c)) and self.buffer_effective[self.buffer_length - 1].diacritic == .empty) {
289	                        // Circumflex.
290	
291	                        // Add circumflex to previous plan 'A' or 'a'.
292	                        self.buffer_effective[self.buffer_length - 1].diacritic = .circumflex;
293	                        // Mark modification index.
294	                        self.buffer_modification_index = self.buffer_length - 1;
295	                    } else if ((self.buffer_effective[self.buffer_length - 1].base == std.ascii.toUpper(c) or self.buffer_effective[self.buffer_length - 1].base == std.ascii.toLower(c)) and self.buffer_effective[self.buffer_length - 1].diacritic == .circumflex) {
296	                        // Cancel circumflex.
297	
298	                        // Reset diacritic to empty.
299	                        self.buffer_effective[self.buffer_length - 1].diacritic = .empty;
300	                        // Mark modification index.
301	                        self.buffer_modification_index = self.buffer_length - 1;
302	
303	                        // Add plan character to buffer_effective.
304	                        // Check if we can add new span for input character.
305	                        if (self.buffer_length < self.buffer_effective.len) {
306	                            // Add character to span.
307	                            self.buffer_effective[self.buffer_length] = Span.init(c);
308	                        }
309	                        // Mark the start of literal input because of the cancelling.
310	                        self.literal_index = self.buffer_length;
311	
312	                        // Increase the buffer length for tracking, we will need it went handling
313	                        // backspace.
314	                        self.buffer_length = self.buffer_length + 1;
315	                    } else {
316	                        unreachable;
317	                    }
318	                }
319	            },
320	            'C', 'c' => {}, // fill missing diacritic, e.g. cước.
321	            'D', 'd' => {}, // bar.
322	            'E', 'e' => {}, // circumflex.
323	            'F', 'f' => {}, // falling.
324	            'I', 'i' => {}, // fill missing diacritic, e.g. người.
325	            'J', 'j' => {}, // falling_glottalized.
326	            'M', 'm' => {}, // fill missing diacritic, e.g. cườm.
327	            'N', 'n' => {}, // fill missing diacritic, e.g. cường.
328	            'O', 'o' => {}, // circumflex.
329	            'P', 'p' => {}, // fill missing diacritic, e.g. cướp.
330	            'R', 'r' => {}, // dipping_rising.
331	            'S', 's' => {}, // rising.
332	            'T', 't' => {}, // fill missing diacritic, e.g. trượt.
333	            'U', 'u' => {}, // fill missing diacritic, e.g. hươu.
334	            'W', 'w' => {}, // breve.
335	            'X', 'x' => {}, // rising_glottalized.
336	            'Z', 'z' => {}, // level / reset.
337	            else => { // literal.
338	                // These characters will be added to state literally.
339	
340	                // Check if we can add new span for input character.
341	                if (self.buffer_length < self.buffer_effective.len) {
342	                    // Add character to span.
343	                    self.buffer_effective[self.buffer_length] = Span.init(c);
344	                }
345	                // Increase the buffer length for tracking, we will need it went handling backspace.
346	                self.buffer_length = self.buffer_length + 1;
347	
348	                // Set modification index to null because we didn't modify any existing span.
349	                self.buffer_modification_index = null;
350	                // Set literal index if it's not set and the length exceed the buffer_effective.
351	                if (self.literal_index == null and self.buffer_length > self.buffer_effective.len) {
352	                    // Set literal mode since buffer index 16 (just after the last buffer_effective
353	                    // item) because we don't have span for these position, we stop processing Telex
354	                    // rules but we will continue processing if user use backspaces to move back to the
355	                    // buffer_effective range, all existing spans must work as expected.
356	                    self.literal_index = self.buffer_effective.len;
357	                }
358	            },
359	        }
360	    }
361	
362	    pub fn backspace(self: *State) void {
363	        // buffer_length must be positive for backspace.
364	        assert(self.buffer_length > 0);
365	
366	        // Input mode must be either .literal or .telex.
367	        assert(self.mode == .literal or self.mode == .telex);
368	
369	        if (self.literal_index) |literal_index| {
370	            // Input mode must be .telex when literal_index is set.
371	            assert(self.mode == .telex);
372	            // literal_index must be within buffer range when set.
373	            assert(literal_index < self.buffer_length);
374	        }
375	
376	        // decrease the buffer_length to match the backspace.
377	        self.buffer_length -= 1;
378	        // b cause backspace doesn't retro-modify the buffer, unset the buffer_modification_index.
379	        self.buffer_modification_index = null;
380	        // if the literal_index is out of buffer range, unset it.
381	        if (self.literal_index != null and self.literal_index.? == self.buffer_length) {
382	            self.literal_index = null;
383	        }
384	    }
385	};
